import React, { useState, useEffect } from 'react';

function Sing() {
  const [debugInfo, setDebugInfo] = useState({});
  const [cookies, setCookies] = useState('');

  useEffect(() => {
    // Обновляем информацию о cookies
    setCookies(document.cookie || 'No cookies');

    // Проверяем все возможные cookie
    const allCookies = {};
    document.cookie.split(';').forEach(cookie => {
      const [key, value] = cookie.trim().split('=');
      if (key) allCookies[key] = value;
    });
    setDebugInfo(prev => ({...prev, allCookies}));
  }, []);

  const testRequest = async () => {
    try {
      const response = await fetch('http://localhost:5000/sings', {
        credentials: 'include'
      });

      setDebugInfo(prev => ({
        ...prev,
        status: response.status,
        statusText: response.statusText,
        headers: Object.fromEntries(response.headers.entries())
      }));
    } catch (error) {
      setDebugInfo(prev => ({...prev, error: error.message}));
    }
  };

  return (
    <div style={{ padding: '20px', fontFamily: 'monospace' }}>
      <h2>Debug Authentication</h2>

      <div style={{ marginBottom: '20px' }}>
        <h3>Cookies:</h3>
        <pre>{cookies}</pre>
        <button onClick={() => setCookies(document.cookie || 'No cookies')}>
          Refresh Cookies
        </button>
      </div>

      <div style={{ marginBottom: '20px' }}>
        <h3>Test Protected Endpoint:</h3>
        <button onClick={testRequest}>Test /api/table</button>
      </div>

      <div>
        <h3>Debug Info:</h3>
        <pre>{JSON.stringify(debugInfo, null, 2)}</pre>
      </div>

      <div style={{ marginTop: '20px', background: '#f0f0f0', padding: '10px' }}>
        <h4>Quick Tests:</h4>
        <button onClick={() => {
          fetch('http://localhost:5000/login', {
            method: 'POST',
            credentials: 'include',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({username: 'admin', password: 'admin'})
          }).then(console.log).catch(console.error);
        }}>
          Test Login
        </button>
      </div>
    </div>
  );
}

export default Sing;

